function SignUpWithGoogleButton() {
  return (
    <Button icon={<GoogleOutlined />} onClick={/* handle sign up with Google */}>
      Sign up with Google
    </Button>
  );
}

export { LoginWithGoogleButton, SignUpWithGoogleButton };
```

